INSERT INTO `wp_postmeta` VALUES (85,41,'titre','Algorithmes & bulles de filtres');
INSERT INTO `wp_postmeta` VALUES (86,41,'_titre','field_olthem_thm_titre');
INSERT INTO `wp_postmeta` VALUES (87,41,'descriptif_desktop','Salut, moi c’est Olga !\r\n\r\nDans cette société de l’immédiateté et de l’information, je dois avouer que je me sens parfois un peu perdue. Qui sont ces algorithmes qui dictent ma pensée ou qui me disent quelle musique écouter? Est-ce que je fais encore des choix sur Internet? Parfois, je me sens un peu enfermée dans une bulle. J’ai l’impression qu’on me balance que ce que j’aime. Au final, je dois la quitter ou pas ma bulle? J’y suis bien, moi, dans ma bulle, avec mes potes, on se comprend..');
INSERT INTO `wp_postmeta` VALUES (88,41,'_descriptif_desktop','field_olthem_thm_descriptif_desktop');
INSERT INTO `wp_postmeta` VALUES (89,41,'descriptif_mobile','Dans cette société de l’immédiateté et de l’information, qui sont ces algorithmes qui dictent ma pensée ou qui me disent quelle musique écouter? Est-ce que je fais encore des choix sur Internet?');
