INSERT INTO `wp_postmeta` VALUES (522,43,'_oembed_4b4d748874ba02af806d6a254ec5b0a9','{{unknown}}');
INSERT INTO `wp_postmeta` VALUES (523,43,'Builder_0_subsection_13_text','Tous pourris ? Les médias nous manipulent ? Pourquoi produisent-ils autant d’infos anxiogènes ? Et qu’est-ce que je peux y faire moi en tant qu’enseignant, que parent ou que jeune… en tant que citoyen ?');
