INSERT INTO `wp_postmeta` VALUES (527,43,'Builder_0_subsection_14_iframe','http:////v.calameo.com/?bkcode=0063496395118feaceb08&language=fr&page=&showsharemenu=true&clickTo=public&clickTarget=_self&clickToUrl=&autoFlip=0&mode=mini&wmode=transparent');
INSERT INTO `wp_postmeta` VALUES (528,43,'_Builder_0_subsection_14_iframe','field_69c73cf3282d9');
INSERT INTO `wp_postmeta` VALUES (529,43,'Builder_0_subsection_15_text','Ce dossier pédagogique apporte des réponses à ces questions en proposant une vision constructive et responsabilisante sans éluder les points d’ombre du journalisme contemporain et des médias en Belgique.\r\n\r\nLa première partie dresse le panorama des médias en Belgique francophone. On y aborde la diversité des médias existants mais aussi la concentration économique des grands titres de presse. On y explore ceux qui utilisent les réseaux sociaux pour produire des informations pertinentes mais aussi le financement de ceux-ci et l’économie de l’attention. La deuxième partie s’intéresse à la place du citoyen dans ces médias. On y évoque les succès et aussi les échecs du «journalisme participatif» avant de décrire d’autres formes de journalisme intéressantes comme le «journalisme constructif» ou le «journalisme de solutions». Enfin, la troisième propose des ateliers ainsi qu’une bibliothèque de ressources qui vous permettront de questionner le fonctionnement des médias actuels et la place des citoyens dans ceux-ci en classe, en famille ou entre amis.\r\n\r\nBonne lecture !');
