INSERT INTO `wp_postmeta` VALUES (583,42,'Builder_0_subsection_1_text','Vous connaissez la dernière ?\r\n\r\nJe serais « complotiste »… Ouais, c’est la réplique facile sur les réseaux sociaux quand on n’a pas  d’arguments ! Tout ça parce que je vois les choses autrement et que j’ai pas envie de tout gober… J’entends tout et son contraire, alors qui croire?\r\n\r\nAprès tout, chacun a le droit de chercher sa vérité, non ?');
INSERT INTO `wp_postmeta` VALUES (584,42,'_Builder_0_subsection_1_text','field_69c4d54bbf536');
INSERT INTO `wp_postmeta` VALUES (585,42,'Builder_0_subsection_1_persotext','1');
INSERT INTO `wp_postmeta` VALUES (586,42,'_Builder_0_subsection_1_persotext','field_69c4d8e087a6b');
INSERT INTO `wp_postmeta` VALUES (587,42,'Builder_0_subsection_1_ignorespacing','0');
INSERT INTO `wp_postmeta` VALUES (588,42,'_Builder_0_subsection_1_ignorespacing','field_69cbeb348ce06');
INSERT INTO `wp_postmeta` VALUES (589,42,'Builder_0_subsection_2_text','« Suis-je complotiste ? » Voilà la question que se pose Théo. Théo, il est un peu perdu car comme il le dit, il entend, il lit, tout… et son contraire. Ça ne vous est jamais arrivé, à vous, de sentir poindre des doutes, des questionnements et de vous dire que la version officielle n’était peut-être pas la “vraie” ? N’avez-vous jamais douté ?\r\n\r\nChemtrails, illuminatis, terre plate, attentats du 11 septembre, complot judéo-maçonnique, et plus récemment, QAnon, le coronavirus et ses vaccins…sont autant de sujets qui peuvent faire sourire, parfois, mais sur lesquels on peut vite en venir à s’écharper…notamment sur les réseaux sociaux.\r\n\r\nLe malaise que soulève le phénomène des théories du complot, toutes catégories d’âge confondues, révèle surtout à quel point il est difficile de faire le tri dans la multitude d’informations que l’on reçoit et combien il devient compliqué de se forger une opinion tout en respectant celles des autres.\r\n\r\nMais avoir un avis, finalement, en quoi est-ce si important ? Devons-nous vraiment en avoir un sur tout et surtout, le partager, et rapidement encore ? Quelles peuvent-être les conséquences de certaines croyances, d’une méfiance accrue envers les discours officiels sur la démocratie, l’engagement citoyen, la santé, notre rapport aux médias ?\r\n\r\nAu travers de ce projet et pour ce deuxième épisode, nous souhaitons donner les clés pour naviguer dans cet océan de doutes sans jamais s’y noyer, baliser le chemin de la construction de soi dans un rapport au monde qui ne soit pas teinté d’un scepticisme exacerbé, s’interroger constamment sur les valeurs que l’on cherche à défendre, certes, mais porter une attention particulière à celles auxquelles d’autres attachent de l’importance. Sans jugement. En privilégiant, outre le dialogue entre soi et soi-même, celui entre soi et les autres.');
INSERT INTO `wp_postmeta` VALUES (590,42,'_Builder_0_subsection_2_text','field_69c4d54bbf536');
