INSERT INTO `wp_postmeta` VALUES (599,42,'Builder_0_subsection_4_text','Diffusée le 1er avril 2021, une émission radio d’une heure est proposée pour revenir sur les concepts de la thématique ! Son objectif? Baliser le projet et donner la parole à des intervenants travaillant le sujet. L’émission sera diffusée sur YouFM et sur nos réseaux sociaux !');
