INSERT INTO `wp_postmeta` VALUES (660,42,'Builder_0_subsection_8_text','Le <strong>30 avril</strong>, nous avons organisé un après-midi spécial<strong> « Théorie du complot » </strong>!\r\n\r\n3 intervenants sont venus nous éclairer sur le sujet :\r\n<ul>\r\n 	<li>Marie Peltier, essayiste et experte en théorie du complot</li>\r\n 	<li>Antonio Solimando, journaliste RTL-TVI</li>\r\n 	<li>Tatiana Debrabandere, chargée de projet au Conseil Supérieur en éducation aux médias</li>\r\n</ul>\r\nLa rencontre fut animée par Mateusz Kukulka.');
