INSERT INTO `wp_postmeta` VALUES (682,42,'Builder_0_subsection_13_text','En partenariat avec <a href=\"https://www.actionmediasjeunes.be/\">Action Média Jeunes</a>, nous vous proposons de vivre une animation en groupe ! Et si on créait un complot pour apprendre à détricoter les autres?\r\n\r\nAprès avoir décrypté les codes et mécanismes à l’œuvre dans les théories du complot, il est temps de les détourner dans une production parodique. Des dates qui lient mystérieusement l’élection de Donald Trump et le lancement de Fortnite à l’étrange coïncidence entre les initiales d’Archibald Haddock et celles d’Adolf Hitler, qui arrivera à mettre sur pied la théorie du complot la plus loufoque ?\r\n<h4 class=\"wp-block-heading\">DÉTAILS PRATIQUES</h4>\r\n<ul>\r\n 	<li>Durée : 1 heure 30 minutes à 3 heures</li>\r\n 	<li>Nombre : de 5 à 15 jeunes</li>\r\n 	<li>Age : 15-25 ans</li>\r\n 	<li>Prix : Gratuit dans le cadre du projet On n’a que l’info qu’on se donne</li>\r\n 	<li>Infos et réservation? info@mundaneum.be</li>\r\n</ul>');
