INSERT INTO `wp_postmeta` VALUES (707,40,'Builder_0_subsection_1_text','Souvent perçue comme un outil redoutable pour façonner les opinions et comportements, la propagande se faufile au coeur de nos sociétés. Elle est une « une tentative délibérée et systématique de façonner les perceptions, manipuler les capacités cognitives et contrôler le comportement de son récepteur afin de s’assurer une réponse qui serve l’intention souhaitée par le propagandiste »\r\n\r\n(Debras, 2024).');
