INSERT INTO `wp_postmeta` VALUES (891,44,'Builder_0_subsection','a:14:{i:0;s:9:\"imagesolo\";i:1;s:8:\"textbloc\";i:2;s:15:\"paragraphetitle\";i:3;s:8:\"textbloc\";i:4;s:9:\"videosolo\";i:5;s:15:\"paragraphetitle\";i:6;s:8:\"textbloc\";i:7;s:13:\"imagegallerie\";i:8;s:15:\"paragraphetitle\";i:9;s:8:\"textbloc\";i:10;s:15:\"paragraphetitle\";i:11;s:8:\"textbloc\";i:12;s:6:\"iframe\";i:13;s:9:\"buttonpdf\";}');
INSERT INTO `wp_postmeta` VALUES (892,44,'_Builder_0_subsection','field_69c4c745e4070');
INSERT INTO `wp_postmeta` VALUES (893,44,'Builder_0_subsection_1_text','C’est un fait : notre société est diversifiée. Les individus qui la composent sont nombreux et différents selon de nombreux critères. Et pour rendre compte de cette diversité, on compte sur les infos que nos médias d’information comme la télévision, la radio ou encore les magazines et journaux diffusent.\r\n\r\nPourtant, avec un peu d’analyse, on réalise qu’ils offrent une vision du monde plutôt restrictive. En effet, ils sont considérés comme des filtres sur la réalité : ce sont eux qui décident des informations qui sont transmises aux citoyens et citoyennes (gate keeping) et la manière dont celles-ci sont véhiculées. Et c’est là que le bât blesse : les médias fonctionnent selon des normes qui favorisent, avantagent et valorisent une catégorie de personnes, laissant souvent de côté les groupes minoritaires. Et de surcroît, les stigmatisent dans des rôles et des fonctions qui renforcent les stéréotypes et favorisent les discriminations.');
INSERT INTO `wp_postmeta` VALUES (894,44,'_Builder_0_subsection_1_text','field_69c4d54bbf536');
