INSERT INTO `wp_postmeta` VALUES (899,44,'Builder_0_subsection_2_paragraphename','Le podcast !');
INSERT INTO `wp_postmeta` VALUES (900,44,'_Builder_0_subsection_2_paragraphename','field_69c72efc6a921');
INSERT INTO `wp_postmeta` VALUES (901,44,'Builder_0_subsection_3_text','On fait le point sur la diversité dans les médias ! Qu’est ce que c’est? Pourquoi est-ce important? Quelles sont les pistes de solutions?\r\nEcoutez l’opinion de nos expertes Cassiopée Hénaff, Manon Libert ( Umons), Camille Laville ( CSA), Salwa Boujour.\r\nUne production du Mundaneum et du Club de la Presse du Hainaut-Mons-Belgique dans le cadre du projet “On n’a que l’info qu’on se donne”. Un projet financé par la Cellule de Promotion de la Citoyenneté et l’interculturalité de la Fédération Wallonie Bruxelles.');
