INSERT INTO `wp_postmeta` VALUES (933,44,'Builder_0_subsection_9_text','« Milite sur Insta ! »\r\nQui a dit que les femmes devaient être minces, blanches et épilées ? Que les hommes ne pouvaient pas porter de jupes, devaient être musclés et ne pouvaient pas montrer leurs émotions ? Que pour être heureux·euse, il faut posséder le dernier smartphone et vivre dans un grand appartement à Dubaï ?\r\nLe web 2.0 nous promettait plus de diversité grâce notamment à la participation de chacun·e sur les réseaux. Et pourtant, les comptes Instagram et Tik Tok les plus suivis reprennent les mêmes clichés et injonctions que les magazines des années 90’ et 2000’. Quels sont les moyens de convaincre son audience ? Pourrions-nous utiliser ces mêmes moyens pour défendre des causes telles que l’écologie, le féminisme et la diversité culturelle ?\r\nC’est ce qu’ Action Médias Jeunes vous propose d’analyser et d’expérimenter durant un atelier manuel déconnecté créatif et réflexif qui applique l’esprit du fanzine aux codes contemporains d’Instagram.\r\n\r\nAtelier proposé dans le cadre du projet « On n’a que l’info qu’on se donne » financé par le FWB.\r\nPlus d’info? Envoyez-nous un petit mail par ici : <a href=\"mailto:info@mundaneum.be\" target=\"_blank\" rel=\"noreferrer noopener\">info@mundaneum.be</a>');
INSERT INTO `wp_postmeta` VALUES (934,44,'_Builder_0_subsection_9_text','field_69c4d54bbf536');
