INSERT INTO `wp_postmeta` VALUES (1232,34,'Builder_0_subsection_0_innertitle','Le projet');
INSERT INTO `wp_postmeta` VALUES (1233,34,'_Builder_0_subsection_0_innertitle','field_69d21e27eb888');
INSERT INTO `wp_postmeta` VALUES (1234,34,'Builder_0_subsection_1_text','#jeunes #éducation #Wallonie\r\n\r\n<strong>Le projet aborde l’éducation à la citoyenneté par l’éducation aux médias en développant des ateliers sur les réseaux sociaux, les théories du complot et le journalisme. Mundaneum met en place un cycle d’ateliers et des événements à destination des 15-25 ans, réalise un webdocumentaire et une valise pédagogique pour pérenniser le projet et propose à nouveau des activités dans les classes.</strong>\r\n\r\nLes personnages <a href=\"http://olthem.be/olga-quitte-ta-bulle/\">Olga</a>, <a href=\"http://olthem.be/theo/\">Théo</a> et Mehdi emmèneront les participants dans l’univers des algorithmes, théories du complot et des médias.\r\n\r\nLe projet est organisé grâce au soutien de la cellule de Promotion de la Citoyenneté et de l’Interculturalité de la Fédération Wallonie-Bruxelles. <a href=\"https://pci.cfwb.be/projets-labelises/mundaneum/\">Notre projet sur le site PCI</a>');
