INSERT INTO `wp_postmeta` VALUES (1352,34,'Builder_0_subsection_12_paragraphename','Apocalypse News : inventons le journalisme de demain !');
INSERT INTO `wp_postmeta` VALUES (1353,34,'_Builder_0_subsection_12_paragraphename','field_69c72efc6a921');
INSERT INTO `wp_postmeta` VALUES (1354,34,'Builder_0_subsection_13_text','<em>Tous les jours, on entend parler de fake news, de la méfiance envers les médias… </em><em>Et si, demain, il n’y avait plus de journalistes, plus de presse ? Comment , dès lors,  faire circuler les infos ? Quelles sont les alternatives ? Et surtout , quels sont les médias dont nous rêvons pour le futur ?</em>\r\n\r\nLe projet<strong> Apocalypse News</strong> propose aux étudiants de 15-25 ans d’imaginer les médias de demain !\r\n\r\nAu terme du projet 20 projets de médias ont été proposé par les étudiants, de quoi inspirer le journalisme de demain !');
