INSERT INTO `wp_postmeta` VALUES (1897,37,'_Builder','field_69aef24b28175');
INSERT INTO `wp_postmeta` VALUES (1898,37,'Builder_1_subsection_1_text','Envie d’organiser un atelier dans votre école, votre association ou votre structure jeunesse ? Nous proposons des ateliers participatifs autour des médias, des réseaux sociaux et de l’esprit critique, pour les 15-25 ans.\r\n\r\nLes ateliers peuvent se dérouler chez vous ou directement au <strong>Mundaneum</strong>. Vous choisissez le thème parmi ceux proposés sur le site, dont certains prennent vie à travers des personnages inspirés des jeunes d’aujourd’hui, plongés dans les médias et les réseaux de notre époque.\r\n\r\nLors de votre demande, vous indiquez une période qui vous convient : un membre de l’équipe vous recontacte ensuite pour fixer ensemble la date précise et les modalités.');
